// CleaningJobs sheet has 'status' (not cleaningStatus). Keep only PENDING, no cleaner assigned, no event yet, processingFlag empty (row-level lock).
const items = $input.all();
const filtered = items.filter(item => {
  const j = item.json || {};
  const status = (j.status ?? '').toString().trim();
  const cleanerId = (j.cleanerId ?? '').toString().trim();
  const hasEvent = (j.calendarEventId ?? '').toString().trim() !== '';
  const processingFlag = (j.processingFlag ?? '').toString().trim();
  return status === 'PENDING' && cleanerId === '' && !hasEvent && processingFlag === '';
});
return filtered;

// Attach Properties, CleanersProfile, and ALL CleaningJobs so Assign Cleaner can do availability checks inside the loop.
let properties = [];
let cleaners = [];
let allJobs = [];
try {
  const pNode = $('Read Properties');
  if (pNode && typeof pNode.all === 'function') properties = pNode.all();
} catch (_) {}
try {
  const cNode = $('Read CleanersProfile');
  if (cNode && typeof cNode.all === 'function') cleaners = cNode.all();
} catch (_) {}
try {
  const jNode = $('Read All Cleaning Jobs');
  if (jNode && typeof jNode.all === 'function') allJobs = jNode.all();
} catch (_) {}
const items = $input.all();
return items.map(item => ({ json: {
  ...item.json,
  _properties: Array.isArray(properties) ? properties : [],
  _cleanersProfile: Array.isArray(cleaners) ? cleaners : [],
  _allCleaningJobs: Array.isArray(allJobs) ? allJobs : []
} }));

// If Lookup returned 0 rows or empty row, use job only with fallbacks. Otherwise use first lookup row.
// propertyName: use reservation lookup first; else get from Properties sheet row matching propertyUid; else fallback to propertyUid.
const job = $('Split In Batches').last().json;
const items = $input.all();
const hasReservation = items.length > 0 && items[0].json?.bookingUid;
const lookup = hasReservation ? items[0].json : {};
let propertyName = (lookup.propertyName ?? '').toString().trim();
if (!propertyName && Array.isArray(job._properties)) {
  const pu = (job.propertyUid ?? '').toString().trim();
  const propRow = job._properties.find(r => {
    const j = r?.json ?? r;
    return (j?.propertyUid ?? '').toString().trim() === pu;
  });
  if (propRow) {
    const j = propRow?.json ?? propRow;
    propertyName = (j?.propertyName ?? '').toString().trim();
  }
}
if (!propertyName) propertyName = (job.propertyUid ?? '').toString().trim();
const merged = { ...job, ...lookup, propertyName, address: lookup.address ?? job.address ?? 'Address TBD' };
return [{ json: merged }];

// Merge cleaning job (from Split In Batches) with reservation (from Ensure One Item).
const job = $('Split In Batches').last().json;
const lookup = $input.first().json;
const merged = { ...job, ...lookup };
return [{ json: merged }];
